mapper.delete:
/** CmmtBoardAuthorityDao.delete_board */
delete from cmmt_board_authority
where
	board_id = #{boardId}

mapper.select:
/** CmmtBoardAuthorityDao.selectList */
select

from cmmt_board_authority cba
where
	board_id = #{boardId}

mapper.update:
/** CmmtBoardAuthorityDao.save */
insert into cmmt_board_authority (
	 board_id
	,authority_id
	,board_authority
	,creator_id
	,created_dt
) values (
	 #{boardId}
	,#{authorityId}
	,#{boardAuthority}
	,#{creatorId}
	,#{createdDt}
) on conflict (board_id, authority_id)
do update set
	 board_authority = #{boardAuthority}
	,creator_id      = #{creatorId}
	,created_dt      = #{createdDt}

mapper.insert:
/** CmmtBoardAuthorityDao.insertList */
insert into cmmt_board_authority (
	 board_id
	,authority_id
	,board_authority
	,creator_id
	,created_dt
) values

	(
		 #{item.boardId}
		,#{item.authorityId}
		,#{item.boardAuthority}
		,#{item.creatorId}
		,#{item.createdDt}
	)

mapper.select:
/** CmmtBoardAuthorityDao.select */
select

from cmmt_board_authority cba
where
	board_id = #{boardId}
	and authority_id = #{authorityId}
